

select distinct
  (select id from users offset floor(random()*100)::int limit 1),
  (select id from posts offset floor(random()*150)::int limit 1)
from generate_series(1, 300)
on conflict do nothing;

select distinct
  (select id from users offset floor(random()*100)::int limit 1) as follower,
  (select id from users offset floor(random()*100)::int limit 1) as following
from generate_series(1, 200)
on conflict do nothing;
